import{_ as e,o,c as l,ag as r}from"./chunks/framework.BbyMWZAR.js";const P=JSON.parse('{"title":"CDN 原理、回源与 OSI 七层模型","description":"","frontmatter":{"title":"CDN 原理、回源与 OSI 七层模型","difficulty":"medium","tags":["CDN","回源","OSI","网络"],"estimate":20},"headers":[],"relativePath":"domains/browser/qa/qa-16-cdn-osi.md","filePath":"domains/browser/qa/qa-16-cdn-osi.md","lastUpdated":1783504823000}'),i={name:"domains/browser/qa/qa-16-cdn-osi.md"};function a(n,t,d,s,c,g){return o(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="问答-16-进阶-cdn-原理、回源与-osi-七层模型" tabindex="-1">问答 16（进阶）：CDN 原理、回源与 OSI 七层模型 <a class="header-anchor" href="#问答-16-进阶-cdn-原理、回源与-osi-七层模型" aria-label="Permalink to &quot;问答 16（进阶）：CDN 原理、回源与 OSI 七层模型&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>CDN 是什么，工作原理是什么？「回源」是指什么？顺便回答 OSI 七层模型每一层负责什么，常见协议属于哪层？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>CDN 是什么</strong></p><ul><li>Content Delivery Network，内容分发网络。核心思想：<strong>把内容放到离用户最近的边缘节点</strong>，减少 RTT、缓解源站压力。</li><li>用户请求会被 DNS / Anycast 路由到最近的 CDN 边缘（PoP，Point of Presence）。</li></ul><p><strong>工作流程</strong></p><ol><li>用户访问 <code>img.example.com/a.png</code>。</li><li>DNS 把 <code>img.example.com</code> CNAME 到 CDN 服务商（如 <code>img.example.com.cdn.foo.com</code>）。</li><li>CDN 智能 DNS 根据用户 IP、运营商、延迟返回最近边缘节点 IP（或用 Anycast 让路由天然收敛到最近节点）。</li><li>边缘节点检查本地缓存： <ul><li><strong>命中</strong> → 直接返回。</li><li><strong>未命中</strong> → <strong>回源</strong>：向上一级（region 缓存）或源站请求内容，缓存到边缘后返回给用户。</li></ul></li><li>后续用户访问同一资源就直接命中边缘缓存。</li></ol><p><strong>关键概念</strong></p><ul><li><strong>回源（back-to-origin）</strong>：边缘节点没缓存或缓存过期时，主动去源站取内容。回源率过高说明缓存效果差。</li><li><strong>缓存 key</strong>：默认是 URL，可加 Host、部分 Query、Cookie；一般去掉带查询参数的动态部分。</li><li><strong>缓存策略</strong>：源站 <code>Cache-Control</code> 决定边缘缓存时长；也可在 CDN 后台覆盖。</li><li><strong>主动刷新（Purge） vs 预热（Preheat）</strong>： <ul><li>Purge：让边缘缓存失效，下次访问回源。</li><li>Preheat：批量把资源推到边缘，避免上线首访冷启动。</li></ul></li><li><strong>静态 vs 动态 CDN</strong>： <ul><li>静态：<code>.js / .css / 图片 / 视频</code>，命中率高。</li><li>动态：API 加速，通过全球骨干网 + TCP 优化（BGP Anycast、连接池、TLS 会话复用）减少延迟，不做缓存或做很短的缓存。</li></ul></li><li><strong>回源保护</strong>：源站前放 shield 层（region cache），把回源压力聚合到一台，避免边缘并发回源打爆源站（cache stampede）。</li></ul><p><strong>收益</strong></p><ul><li>就近访问，RTT 从几百 ms 降到几十 ms。</li><li>减轻源站带宽 / QPS 压力。</li><li>抗 DDoS：边缘节点分散流量，配合 WAF 清洗。</li><li>HTTPS 握手在边缘完成，用户到边缘 RTT 短，握手快。</li></ul><p><strong>OSI 七层模型</strong></p><table tabindex="0"><thead><tr><th>层</th><th>数据单位</th><th>主要职责</th><th>典型协议</th></tr></thead><tbody><tr><td>7. 应用层</td><td>消息</td><td>具体应用协议</td><td>HTTP、HTTPS、FTP、SMTP、DNS、WebSocket、gRPC</td></tr><tr><td>6. 表示层</td><td>数据</td><td>编码 / 加密 / 压缩</td><td>TLS/SSL（一般归到 5-6 层之间）、JPEG、ASCII</td></tr><tr><td>5. 会话层</td><td>数据</td><td>会话管理</td><td>RPC、NetBIOS</td></tr><tr><td>4. 传输层</td><td>段 / 数据报</td><td>端到端可靠 / 无连接</td><td>TCP、UDP、QUIC</td></tr><tr><td>3. 网络层</td><td>包</td><td>路由与寻址</td><td>IP、ICMP、路由协议</td></tr><tr><td>2. 数据链路层</td><td>帧</td><td>相邻节点数据传输</td><td>Ethernet、PPP、ARP</td></tr><tr><td>1. 物理层</td><td>比特</td><td>电信号 / 光信号</td><td>网线、光纤、无线电</td></tr></tbody></table><ul><li>实际工程更常用 <strong>TCP/IP 四层模型</strong>：应用层 / 传输层 / 网络层 / 网络接口层。</li><li>面试记忆口诀：<strong>应表会传网数物</strong>（应用、表示、会话、传输、网络、数据链路、物理）。</li></ul><h2 id="追问-1-cdn-上出现「缓存不一致-用户看到老版本」怎么排查" tabindex="-1">追问 1：CDN 上出现「缓存不一致 / 用户看到老版本」怎么排查？ <a class="header-anchor" href="#追问-1-cdn-上出现「缓存不一致-用户看到老版本」怎么排查" aria-label="Permalink to &quot;追问 1：CDN 上出现「缓存不一致 / 用户看到老版本」怎么排查？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>常见原因和排查： <ol><li>静态资源没带 hash，命名和内容脱钩：改成 <code>app.a1b2c3.js</code> 类名。</li><li>HTML 缓存太久：HTML 短缓存（<code>max-age=60</code> 或 <code>no-cache</code>），静态资源长缓存。</li><li><code>Vary</code> 缺少关键维度：如按 UA / Accept-Language 返回不同内容却没设 Vary，导致误命中。</li><li>部署后没刷新 CDN：发布流水线里接入 CDN Purge。</li><li>边缘节点各自缓存，某个节点回源失败仍返回旧内容：查看 CDN 后台各节点命中日志。</li><li>客户端本地磁盘缓存：观察响应头 <code>age</code>、<code>x-cache</code>，或 Ctrl+Shift+R 强制刷新验证。</li></ol></li><li>应急：Purge 特定 URL；治本：文件名带 hash + 缓存策略分级 + 发布自动化。</li></ul><h2 id="追问-2-为什么静态资源常常放独立域名-例如-static-example-com-甚至-cookie-free-域名" tabindex="-1">追问 2：为什么静态资源常常放独立域名（例如 <code>static.example.com</code>），甚至 cookie-free 域名？ <a class="header-anchor" href="#追问-2-为什么静态资源常常放独立域名-例如-static-example-com-甚至-cookie-free-域名" aria-label="Permalink to &quot;追问 2：为什么静态资源常常放独立域名（例如 `static.example.com`），甚至 cookie-free 域名？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>减少 Cookie 传输</strong>：主域下的 Cookie（用户登录态）在请求 <code>example.com</code> 上的每个资源时都会带；把静态资源放独立域名（不设 Cookie）能节省大量带宽。</li><li><strong>绕过浏览器同域连接数限制</strong>（HTTP/1.1 每域 6 个）：多域并发下载。HTTP/2 时代此收益减弱。</li><li><strong>独立缓存策略 / CDN 加速</strong>：静态域名指向 CDN，主域走应用网关。</li><li><strong>安全</strong>：静态内容和动态 API 域名隔离，方便应用不同的 CSP / CORS / Cookie 策略。</li><li><strong>代价</strong>：多一次 DNS + TCP + TLS 握手；HTTP/2 下要注意 SNI / 证书 / 连接合并。</li></ul><h2 id="追问-3-tcp-ip-四层和-osi-七层如何对应-tls-在哪一层" tabindex="-1">追问 3：TCP/IP 四层和 OSI 七层如何对应？TLS 在哪一层？ <a class="header-anchor" href="#追问-3-tcp-ip-四层和-osi-七层如何对应-tls-在哪一层" aria-label="Permalink to &quot;追问 3：TCP/IP 四层和 OSI 七层如何对应？TLS 在哪一层？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>对应： <ul><li>应用层 ≈ OSI 5-7 层。</li><li>传输层 = OSI 4 层。</li><li>网络层 = OSI 3 层。</li><li>网络接口层 = OSI 1-2 层。</li></ul></li><li><strong>TLS</strong> 的定位有争议： <ul><li>严格来说它跑在 TCP 之上、HTTP 之下，属于 OSI 的 <strong>表示层（6）</strong> 或介于 4 和 7 之间。</li><li>IETF 常称之为「应用层协议」，因为它对应用透明地提供加密。</li><li>HTTPS 里就是「HTTP over TLS over TCP over IP」的分层结构。</li></ul></li><li>QUIC 更特殊：把 TLS 1.3 内置到自己里，跑在 UDP 上，同时替代 TCP + TLS 一部分职能。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://hpbn.co/content-delivery/" target="_blank" rel="noreferrer">hpbn.co: Content Delivery</a>：CDN 原理与回源机制</li><li><a href="https://developer.mozilla.org/en-US/docs/Glossary/CDN" target="_blank" rel="noreferrer">MDN: Content delivery networks</a>：CDN 概念与缓存层级</li><li><a href="https://www.w3.org/TR/resource-hints/" target="_blank" rel="noreferrer">W3C: Resource Hints</a>：dns-prefetch、preconnect 等提示</li></ul>',27)])])}const p=e(i,[["render",a]]);export{P as __pageData,p as default};
